                keyValue: 2,
                columns: new[] { "AuthorName", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. يوسف المنصور", "رحلة عبر المخطوطات والوثائق التاريخية لفهم كيف تم تدوين تاريخ الأندلس. الأندلس كانت حضارة متقدمة وغنية بالثقافات المتعددة، لكن كيف تم تدوين تاريخها؟ هل كانت الروايات التاريخية موثوقة أم أن كل مؤرخ أضاف لمسته الخاصة؟\r\n\r\nالمخطوطات الأندلسية تخبرنا الكثير عن الحياة في تلك الفترة. ابن حزم، الطبري، المقري وغيرهم من المؤرخين الأندلسيين تركوا لنا سجلات مفصلة عن الأحداث والحياة اليومية. لكن هذه الروايات تختلف أحياناً، مما يثير أسئلة حول الحقيقة والتفسير.\r\n\r\nالتاريخ ليس حقيقة مطلقة، بل هو تفسير من قبل شهود أو مؤرخين. كل راوٍ يختار التفاصيل التي يراها مهمة، ويترك جانباً ما يعتبره ثانوياً. هذا يعني أن تاريخ الأندلس الذي نعرفه اليوم هو انعكاس لاختيارات المؤرخين الأندلسيين وليس الحقيقة المطلقة.\r\n\r\nالخيال أيضاً لعب دوراً في تدوين التاريخ. الشعر والأدب كانا طرقاً للتعبير عن الأحداث التاريخية. القصائد والقصص الأدبية ساهمت في نقل الروح الحقيقية للعصر، حتى لو لم تكن دقيقة من الناحية الحرفية.\r\n\r\nعندما نقرأ تاريخ الأندلس اليوم، نحن نقرأ خليطاً من الحقيقة والخيال، من السجلات الموثوقة والرويات الملونة. هذا المزيج هو الذي يعطي لتاريخ الأندلس عمقه وجماله. نحن لا نتعرف على حقائق جافة، بل على قصة حية وممتعة.\r\n\r\nفهم هذا الفرق مهم لمن يدرس التاريخ. يجب أن نقرأ المصادر الأصلية بعين ناقدة، وأن نحاول فهم سياق كل رواية. يجب أن نقدر الجهد الذي بذله المؤرخون القدماء في حفظ ذاكرة حضارتهم.\r\n\r\nالأندلس تبقى واحدة من أعظم الحضارات في التاريخ، وتدوينها ظل أحد أعظم الإنجازات في تاريخ الكتابة التاريخية. مزجها بين الدقة والجمال، بين الحقيقة والخيال، أعطاها نسيجاً فريداً من نوعه.", new DateTime(2024, 5, 12, 0, 0, 0, 0, DateTimeKind.Utc), "https://lh3.googleusercontent.com/aida-public/AB6AXuDvTOcb-4WoMNK3FNHOWAcTbvAFvAD0hiv1psKJfVJwybTcPE53lT5uI4ykosZhyRTIspUWKuhLGxv5Z9Cs6mps1oc44soP13Ya5kISixiw8_iuWR74l-ZiTu5vTztHb4eiQEIlO7ub5EY4AdtEcsFQwSEnwkEjld2rTDx1QuKRBZpqRUoyNc3ziDBSh9759mJ_3sF0LQYe0tiPbQp9XIs4czw-w-bS0Wir1NOEfQZ4J__rQnpI-WbTNij60X-9ZG3tM53Krumer9Sk", "بين الحقيقة والخيال: تدوين التاريخ في الأندلس" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 3,
                columns: new[] { "AuthorName", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "أ. ليلى حسن", "استكشاف تاريخ المجالس الأدبية في العواصم العربية ودورها في إثراء الثقافة. المجالس الأدبية كانت مراكز إشعاع ثقافي في عواصمنا العربية. في هذه المجالس، كان يجتمع الأدباء والشعراء والفلاسفة لمناقشة الأفكار وتبادل الآراء.\r\n\r\nمجالس بغداد في العصر العباسي كانت أسطورية. هنا التقى الكندي والفارابي والجاحظ وغيرهم من الفلاسفة والكتاب العظماء. كانوا يناقشون الفلسفة واللغة والأدب والعلوم. هذه المجالس أنتجت أعظم الأعمال الفكرية للحضارة الإسلامية.\r\n\r\nفي دمشق والقاهرة وقرطبة، كانت هناك مجالس أدبية متشابهة. في الأندلس، كانت مجالس الأمراء والعلماء مراكز للحوار الثقافي. المعتمد بن عباد، على سبيل المثال، كان يجمع حوله الشعراء والعلماء في مجالسه الشهيرة.\r\n\r\nهذه المجالس لم تكن مجرد اجتماعات اجتماعية. كانت مراكس للبحث والتطور الفكري. هنا ولدت الأفكار الجديدة، وتم نقد الأفكار القديمة. هنا تم تشكيل الذوق الأدبي والفكري لأجيال.\r\n\r\nالحوار في هذه المجالس كان حراً وتفاعلياً. كان الاختلاف في الرأي مقبولاً بل مرحباً به. هذه الحرية الفكرية أدت إلى إثراء الثقافة والأدب. من هنا خرجت أعظم الروائع الأدبية والفكرية.\r\n\r\nاليوم، مجالس الأدب أصبحت أقل شيوعاً. الإنترنت والوسائط الرقمية غيرت طريقة حوارنا. لكن هناك محاولات لاستعادة روح المجالس الأدبية التقليدية. في دول عربية مختلفة، هناك مجالس أدبية تحاول أن تحافظ على التقليد القديم.\r\n\r\nذاكرة هذه المجالس ما زالت حية في تراثنا الأدبي. الحوارات التي دارت فيها، الأفكار التي ولدت فيها، كل هذا بقي محفوظاً في المخطوطات والمؤلفات. قراءة هذه المخطوطات تعيدنا إلى عالم مختلف من الحوار الثقافي الغني.", new DateTime(2024, 5, 8, 0, 0, 0, 0, DateTimeKind.Utc), "https://lh3.googleusercontent.com/aida-public/AB6AXuDnKRzkjPE9Aa-O8S8G4O93mMJ6EWDq7GGhlK16BDgkglA9Jf9ohWLiD27FiI15QakRI2kKzxX-1kRd6M9_jTQ0wo1RtH6whXEMJuCkne87RfpMDeebo63iIL66vaZaxXY3o3oXw6K5nd--ZEyD3H95zaQXU_O1ib9l5Y7vJGbi5nv5k6zkdWETfluxuPBvhLIyZ-KJJsFLF17hfCt-VgBGqD9GWO6Lss3rfVdyLFbWdpahbR-ifnaa1WrzqXAHbsOuJeGlrWGShubr", "مجالس الأدب في العواصم العربية: ذاكرة الحوار" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 4,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "أ. سارة الراشد", 1, "نقاش معمّق حول تأثير تقنيات الذكاء الاصطناعي على الهوية الثقافية العربية. الذكاء الاصطناعي يغير طريقة تفكيرنا وعملنا وتعاملنا مع العالم. لكن ماذا عن تأثيره على هويتنا الثقافية؟\r\n\r\nالتكنولوجيا لطالما كانت أداة للتبديل الثقافي. الطباعة غيرت طريقة نشر المعرفة. الإذاعة والتلفاز غيرا طريقة استقبالنا للمعلومات والثقافة. الإنترنت فتح آفاقاً جديدة للتبادل الثقافي. والآن، الذكاء الاصطناعي يأتي بتأثيرات جديدة ومختلفة.\r\n\r\nمن جهة، الذكاء الاصطناعي يمكنه أن يساهم في الحفاظ على الثقافة العربية. يمكن استخدامه لحفظ النصوص القديمة، لترجمة الأعمال الأدبية، لتطوير محررات نصية تدعم اللغة العربية بشكل أفضل. التطبيقات التعليمية القائمة على الذكاء الاصطناعي يمكنها أن تعلم الأجيال الجديدة عن تراثنا.\r\n\r\nلكن من جهة أخرى، هناك تهديدات حقيقية. الخوارزميات التي تدفع بنا نحو محتوى معين قد تحد من تنوعنا الثقافي. إذا كانت معظم الذكاء الاصطناعي مبني على البيانات الغربية، فقد ينعكس هذا في المحتوى الذي يتم توليده. الثقافة العربية قد تصبح هامشية في عالم يحكمه الذكاء الاصطناعي.\r\n\r\nهناك أيضاً مسألة الملكية الثقافية. عندما يتم استخدام الأعمال الأدبية العربية القديمة لتدريب نماذج الذكاء الاصطناعي، من يستفيد من هذا؟ هل حقوق المؤلفين والثقافة محمية؟\r\n\r\nالحقيقة أن الذكاء الاصطناعي بحد ذاته لا يهدد ولا ينقذ الهوية الثقافية. كل يتعلق بكيفية استخدامنا له. إذا استخدمناه بحكمة، يمكن أن يكون أداة قوية لنشر وحفظ ثقافتنا. لكن إذا تركنا له الحبل على الغارب، قد نجد أنفسنا نسير بدون اتجاه.\r\n\r\nنحتاج إلى مناقشات جادة حول كيفية استخدام الذكاء الاصطناعي بطريقة تحافظ على هويتنا الثقافية. نحتاج إلى تطوير نماذج ذكاء اصطناعي عربية مبنية على قيمنا وثقافتنا. نحتاج إلى الحفاظ على السيطرة على أدواتنا، بدلاً من السماح لها بالسيطرة علينا.", new DateTime(2024, 5, 5, 0, 0, 0, 0, DateTimeKind.Utc), "https://lh3.googleusercontent.com/aida-public/AB6AXuBhLMRuyipwroCSKOsyhP0lA5dVBI4Dq9GPVGay4QTwlSpTCSq8_KbmReL0b0k-lskINCCJ_WVXMTkIwA-wwZDQDyMyx03lX4M3m2awmNqOiiIjIT0eaceEIeInzxSq5QCJsIdldPJyqyJX-yL4Ug82heunZRrc7oIEorvN6ChFbjUcCKtpggpNAYgZFQe51T_nDYWKYwzbxRW7cYyTAymM6YRuwu5eQXmDNVKgt4TfA_JX0VnbKm94gn1eg_EqWRI3fLnH6cbz_nMu", "الذكاء الاصطناعي: هل يهدد الهوية الثقافية؟" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 5,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. عمر القاسم", 13, "نظرة عميقة في الجذور الفكرية وكيف ساهمت في تشكيل الوعي المعاصر، مستكشفين الفراغ والضوء كعناصر روحية قبل أن تكون مادية. العمارة الإسلامية ليست مجرد عن بناء المساجد والقصور، بل هي تعبير عن رؤية كاملة للعالم.\r\n\r\nالفراغ في العمارة الإسلامية لم يكن فراغاً فارغاً. كان فراغاً مقصوداً، معبراً عن اللانهاية والخلود. الصحن الكبير في المسجد، المساحات المفتوحة بين الأعمدة، كل هذا كان جزءاً من فلسفة معينة. كانت العمارة الإسلامية تعلمنا أن الفراغ يمكن أن يكون له معنى، وأن الصمت يمكن أن يكون له صوت.\r\n\r\nالضوء أيضاً كان عنصراً روحياً في العمارة الإسلامية. الضوء الذي يخترق النوافذ الصغيرة والكبيرة، الظل الذي ينشأ من الأقواس والقباب، كل هذا كان جزءاً من تجربة روحية. المعمار الإسلامي كان يفهم أن الضوء والظل يمكنهما أن يؤثرا على الروح والعقل.\r\n\r\nالزخرفة الهندسية في العمارة الإسلامية لم تكن مجرد زينة. كانت محاولة لتمثيل الانسجام والنظام الكوني. الأنماط المتكررة، الأشكال الهندسية المعقدة، كل هذا كان انعكاساً لفهم عميق للرياضيات والفلسفة.\r\n\r\nالمسجد الإسلامي كان مساحة للتأمل والروحانية. ليس فقط بسبب الدين، بل أيضاً بسبب الطريقة التي تم تصميمها. المعماري الإسلامي كان يريد أن ينقل الإنسان من عالم الدنيا المادي إلى عالم روحاني أعلى. كل عنصر معماري كان جزءاً من هذه الرحلة.\r\n\r\nاليوم، يمكننا أن نتعلم الكثير من هذه الفلسفة المعمارية. في عالم يصرخ من الضوضاء والفوضى، يمكننا أن نجد السلام والهدوء في الفراغات المصممة بحكمة. في عالم يحتفي بالحشو والامتلاء، يمكننا أن نجد الجمال في البساطة والخطوط النظيفة.\r\n\r\nعمارة الروح الإسلامية تعلمنا أن العمارة ليست مجرد شكل وأسمنت، بل هي تجربة كاملة، تأثير على الروح والعقل والجسد. هذا الفهم العميق هو ما يميز العمارة الإسلامية ويجعلها خالدة.", new DateTime(2024, 5, 20, 0, 0, 0, 0, DateTimeKind.Utc), "https://lh3.googleusercontent.com/aida-public/AB6AXuAGaMizZifHeSWvvhp1FkJga8F5up4hBKUMUH-VMa1wk6VJ2-EjtLe984hkBoyUTPDlBJmFmIiKDDnTDZJy9g1H-AXNfVHaxnnK8DakMOoGV_ndmBUJAwEXYE-Y9d3mg2yNR1bi7EuJBKI640IIf4MhHyZYquCpEhMPOQUsnnb0pyypJUMi9JlX80vL1wBnbOCYQduWkgFmiZIJUjMDuOImss_626cy6ug3PVaMqGyqNQawEdvbcOSlhYASY0fjDsNGn014eWTQrqG5", "عمارة الروح: تأملات في الفلسفة المعمارية الإسلامية" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 6,
                columns: new[] { "AuthorName", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. أحمد السيد", "استكشاف مفهوم الزمن في التراث الصوفي والتفسيرات المختلفة للزمن الروحي. الصوفيون القدماء لم ينظروا إلى الزمن كما نظرنا إليه نحن في العصر الحديث. الزمن لم يكن مجرد ساعات ودقائق، بل كان تجربة وحالة روحية.\r\n\r\nفي الفكر الصوفي، الزمن لديه أبعاد متعددة. هناك الزمن الخارجي، زمن الساعة والتاريخ. وهناك الزمن الداخلي، زمن الروح والقلب. الصوفي كان يسعى للتجاوز من الزمن الخارجي إلى الزمن الداخلي، من المادي إلى الروحي.\r\n\r\nالصوفيون تحدثوا عن حالات يختفي فيها الزمن تماماً. في لحظات من التأمل العميق أو الانجذاب الروحي، يشعر الصوفي أنه خارج الزمن. اللحظة تصبح أبدية، والأبدية تصبح حاضرة الآن.", new DateTime(2024, 5, 18, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Sufi+Thought", "مفهوم الزمن في الفكر الصوفي القديم" });

            migrationBuilder.UpdateData(
