                keyValue: 7,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. سارة محمود", 13, "دراسة حول كيف تجلت الحداثة في الشعر العربي المعاصر وتأثيرها على الشعراء. الشعر العربي المعاصر شهد ثورة حقيقية عندما بدأ الشعراء يتحررون من القيود التقليدية. الشعر الحر والتفعيلة أتاحا للشعراء مساحات أكبر للتجريب والابتكار.\r\n\r\nنزار قباني، أدونيس، سميح القاسم وغيرهم من الشعراء المعاصرين احدثوا ثورة في الشعر العربي. جلبوا لغة جديدة، موضوعات جديدة، أساليب جديدة. الحداثة لم تكن مجرد شكل جديد، بل فلسفة جديدة لفهم الشعر والكتابة.\r\n\r\nالشعر المعاصر أصبح أكثر انفتاحاً على التجارب الشخصية والسياسية والاجتماعية. لا يعود الشاعر ملزماً بمواضيع معينة أو أشكال محددة. الحرية التي جلبتها الحداثة سمحت للشعراء أن يصرخوا من قلوبهم.", new DateTime(2024, 5, 16, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Modern+Poetry", "تجليات الحداثة في الشعر العربي المعاصر" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 8,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "أ. محمد علي", 14, "دراسة حول كيف تؤثر البيئة العمرانية على الوعي والصحة النفسية للإنسان. المدينة ليست مجرد مجموعة من المباني والطرق. المدينة لها روح، وهذه الروح تؤثر على الناس الذين يعيشون فيها.\r\n\r\nالتصميم العمراني يؤثر على الحالة النفسية للإنسان. المدن الضيقة والمزدحمة تخلق ضغوطاً نفسية. المدن الواسعة والمفتوحة تجلب الاستقرار والسلام. الألوان، الأضواء، الأصوات، كل هذا يؤثر على وعينا بطرق قد لا ندركها.", new DateTime(2024, 5, 14, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Urban+Psychology", "سيكولوجية المدن: كيف تؤثر البيئة على الوعي" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 9,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. فاطمة النعمان", 5, "تحليل شامل لتحديات ومستقبل اللغة العربية في عصر العولمة والتكنولوجيا. اللغة العربية تواجه تحديات حقيقية في العصر الحديث. الإنجليزية أصبحت لغة العلم والتكنولوجيا والعمل. الشباب يستخدمون لغة مختلطة، مزيج من العربية والإنجليزية والعامية.\r\n\r\nلكن اللغة العربية لم تمت. هناك محاولات جادة لتطويرها وجعلها تواكب العصر. المعاجم الإلكترونية، التطبيقات التعليمية، المحتوى الرقمي العربي، كل هذا يساهم في الحفاظ على اللغة وتطويرها.\r\n\r\nمستقبل اللغة العربية يعتمد على اهتمام الأجيال الجديدة بها. إذا استطعنا أن نجعل اللغة العربية جذابة وملائمة للعصر، يمكننا أن نضمن بقاؤها وازدهارها.", new DateTime(2024, 5, 11, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Arabic+Language", "مستقبل اللغة العربية في ظل العولمة" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 10,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. محمود الأحمد", 13, "رحلة الكتابة الإبداعية من العصر الكلاسيكي إلى العصر الرقمي. الكتابة الإبداعية تطورت بشكل كبير مع تطور التكنولوجيا. من الورقة والحبر إلى الحاسوب والإنترنت، الكتابة أصبحت أكثر سهولة ولكن أيضاً أكثر تحدياً.\r\n\r\nالكاتب المعاصر يواجه فرصاً جديدة وتحديات جديدة. من جهة، يمكنه أن ينشر أعماله مباشرة للعالم. من جهة أخرى، يجب أن يتنافس مع ملايين الكتاب الآخرين. الجودة أصبحت أكثر أهمية من أي وقت مضى.\r\n\r\nالكتابة الإبداعية اليوم لا تقتصر على الرواية والقصة والشعر. هناك أشكال جديدة مثل الكتابة للإنترنت والتدوين والكتابة للعاب. كل هذه الأشكال تتطلب مهارات جديدة ومنهجيات جديدة.", new DateTime(2024, 5, 10, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Creative+Writing", "الكتابة الإبداعية: من الورقة إلى الشاشة" });
        }

        /// <inheritdoc />
        protected override void Down(MigrationBuilder migrationBuilder)
        {
            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 1,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. محمد العربي", 5, "الدولة الأموية تعتبر من أهم الفترات في التاريخ الإسلامي، حيث شهدت نهضة حضارية وسياسية استثنائية. قامت هذه الدولة العظيمة على أسس قوية من الإدارة والعدل، وامتدت رقعتها الجغرافية من الصين شرقاً إلى الأندلس غرباً، مما جعلها واحدة من أكبر الإمبراطوريات في التاريخ.\r\n\r\nبدأت الدولة الأموية بتأسيس معاوية بن أبي سفيان في سنة 41 هـ، وحكمت لأكثر من مائة سنة من الاستقرار النسبي والتطور الحضاري. كان للخلفاء الأمويين دور كبير في نشر الإسلام وتوسيع حدود الدولة الإسلامية في جميع الاتجاهات. كما قادوا حروباً عديدة ضد الدولة البيزنطية والفرس، مما ترتب عليه توسع كبير في أراضي الدولة الإسلامية.\r\n\r\nمن أهم إنجازات الدولة الأموية هو بناء الحضارة الإسلامية وتطويرها. شهدت هذه الفترة نهضة فكرية وعلمية كبيرة، حيث ازدهرت العلوم المختلفة من الفقه والحديث والتاريخ والجغرافيا والرياضيات والفلك. كما شجع الخلفاء الأمويون الترجمة والتصنيف، مما ساهم في الحفاظ على المعارف اليونانية والفارسية والهندية.\r\n\r\nالعمارة الأموية تركت بصمة واضحة على الحضارة الإسلامية. بنى الأمويون المسجد الأموي في دمشق الذي يعتبر من أعظم المساجد الإسلامية، وقبة الصخرة في القدس، وعدداً من القصور والحصون المعروفة. هذه المنشآت تعكس براعة المعماريين الأمويين وفهمهم العميق للفنون الإسلامية.\r\n\r\nالنظام الإداري الأموي كان نموذجاً متقدماً لعصره. قسم الخلفاء الدولة إلى ولايات، وعينوا والياً لكل ولاية يرأس الإدارة والقضاء والجيش. وضعوا نظاماً متكاملاً للضرائب والمالية، مما سمح بتمويل الجيش والمشاريع العمرانية.\r\n\r\nكانت فترة الخلفاء الراشدين والدولة الأموية مهمة جداً لتطور الشريعة الإسلامية. في هذه الفترة تم تدوين القرآن والسنة بشكل رسمي، وبدأ تطور علوم الفقه الإسلامي. اختلف الفقهاء حول تفسير النصوص والقوانين، مما أدى إلى ظهور المذاهب الفقهية المختلفة.\r\n\r\nالحياة الاجتماعية في العصر الأموي كانت متنوعة ومعقدة. كان هناك طبقات اجتماعية مختلفة من الخلفاء والأمراء والعلماء والفلاحين والعمال. اهتم الأمويون ببناء المدن والعمران، وأسسوا حواضر جديدة مثل البصرة والكوفة وغيرها.\r\n\r\nالاقتصاد الأموي كان قائماً على الزراعة والتجارة. كانت الدولة تتحكم في الطرق التجارية الرئيسية بين الشرق والغرب، مما جعلها مركزاً اقتصادياً مهماً. ازدهرت المدن التجارية مثل دمشق وبغداد وقرطبة، وازداد الاتصال التجاري مع الدول الأجنبية.\r\n\r\nسقوط الدولة الأموية في سنة 132 هـ كان نتيجة عدة عوامل، منها الصراعات الداخلية بين أفراد الأسرة الحاكمة، والضغط من المذاهب الشيعية والخوارج، والثورات الشعبية. لكن إرثها الحضاري ظل تأثيره قائماً في الحضارة الإسلامية لقرون قادمة.\r\n\r\nدراسة الدولة الأموية مهمة جداً لفهم التاريخ الإسلامي والحضارة العربية. فهي تمثل فترة حاسمة في تطور الإسلام والعالم الإسلامي، وتركت إرثاً عظيماً في جميع جوانب الحياة الإنسانية من السياسة والعلوم إلى الفنون والعمارة.", new DateTime(2025, 1, 1, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Umayyad+State", "الدولة الأموية والنهضة الحضارية الإسلامية" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 2,
                columns: new[] { "AuthorName", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. فاطمة الحسيني", "الحروب الصليبية تعتبر من أهم الأحداث التاريخية التي غيرت مسار التاريخ الإسلامي والعالمي. امتدت هذه الحروب من نهاية القرن الحادي عشر إلى نهاية القرن الثالث عشر الميلادي، وكانت بمثابة صراع حضاري وديني بين العالم الإسلامي والعالم المسيحي.\r\n\r\nبدأت الحروب الصليبية عندما أطلق البابا أوربان الثاني نداءه في عام 1095 م لتحرير القدس من المسلمين. استجابت أوروبا لهذا النداء بحماس شديد، وتجهزت جيوش كبيرة من الفرسان والمشاة والعبيد توجهت نحو الشرق الأوسط. كانت هذه الحملات منظمة بشكل جيد وممولة بأموال طائلة من الكنيسة والأمراء الأوروبيين.\r\n\r\nعند وصول الصليبيين إلى الشام والقدس، شنوا هجمات عنيفة على المسلمين. احتلوا القدس في عام 1099 م بعد حصار طويل، وأسسوا مماليك صليبية في الشام. لكن المسلمين لم يستسلموا، وقاموا بثورات عديدة ضد الاحتلال الصليبي. من أهم هذه الثورات كانت قيادة صلاح الدين الأيوبي الذي استطاع توحيد المسلمين وتحرير القدس في عام 1187 م.\r\n\r\nكان لهذه الحروب تأثير كبير على الحياة الاجتماعية والاقتصادية والسياسية في الشرق الأوسط. أدت إلى هجرة قسرية لآلاف المسلمين والمسيحيين الشرقيين. كما أثرت على طرق التجارة بين الشرق والغرب، مما أدى إلى اضطرابات اقتصادية في كلا الجانبين.\r\n\r\nالحروب الصليبية لم تكن فقط حروباً عسكرية، بل كانت أيضاً حروباً ثقافية وحضارية. جلب الصليبيون معهم تقاليدهم وعاداتهم وأنماط حياتهم، الأمر الذي أدى إلى تأثر الثقافة الإسلامية بعناصر غربية. من جهة أخرى، تأثرت أوروبا بالحضارة الإسلامية من خلال التعامل المباشر مع المسلمين.\r\n\r\nنتج عن الحروب الصليبية ظهور جماعات عسكرية إسلامية جديدة. كان المسلمون يشعرون بالتهديد المستمر، فنظموا أنفسهم في جيوش دائمة. ظهرت فئات من المحاربين المتفرغين مثل الفرسان والمماليك الذين اختصوا بالحرب والدفاع عن الإسلام.\r\n\r\nالتبادل الثقافي الناتج عن الحروب الصليبية كان إيجابياً في بعض جوانبه. أوروبا استقبلت المعارف الإسلامية في الرياضيات والفلك والطب والفلسفة. كما تعرف الأوروبيون على الحضارة الإسلامية الراقية، مما ساهم في نهضة أوروبا لاحقاً.\r\n\r\nكان هناك تعاون وتنافس بين الدول الإسلامية خلال فترة الحروب الصليبية. استطاع المسلمون في بعض الأحيان التعاون ضد العدو المشترك، وفي أحيان أخرى كانت هناك صراعات بينهم. هذا التنافس ضعف الرد الموحد على التهديد الصليبي.\r\n\r\nآثار الحروب الصليبية امتدت عبر القرون. تركت في الذاكرة الجماعية الإسلامية والعربية تأثيراً عميقاً، وأصبحت رمزاً للتضحية والمقاومة. كما أثرت على العلاقات بين الشرق والغرب، وخلقت حساسيات دينية وثقافية استمرت لقرون.", new DateTime(2025, 1, 3, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Crusades", "الحروب الصليبية وتأثيرها على الشرق الأوسط" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 3,
                columns: new[] { "AuthorName", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. سارة الشاعري", "الأدب العربي يعتبر من أعظم الآداب العالمية، وله تاريخ عريق يمتد إلى قبل الإسلام. يعكس هذا الأدب روح الأمة العربية وقيمها وطموحاتها عبر القرون. من الشعر الجاهلي إلى الأدب الحديث، ترك الأدب العربي إرثاً حضارياً غني بالجمال والمعاني.\r\n\r\nالشعر الجاهلي يعتبر من أقدم أشكال الأدب العربي وأكثرها حفظاً. كان الشعراء الجاهليون يستخدمون الشعر للتعبير عن مشاعرهم وأفكارهم وقيمهم. شعراء مثل امرؤ القيس وعنترة والنابغة الذبياني تركوا لنا روائع شعرية تجسد روح العصر. الشعر الجاهلي يتميز باللغة القوية والصور البيانية الجميلة والمشاعر الصادقة.\r\n\r\nبعد الإسلام، تطور الأدب العربي وأخذ أشكالاً جديدة. ظهر شعراء إسلاميون مثل حسان بن ثابت والنابغة الجعدي الذين وظفوا الشعر لخدمة الدعوة الإسلامية. كما ازدهر النثر العربي مع ظهور الخطابة والرسائل والمقامات. اهتم الأدباء المسلمون بنقل العلوم والمعارف من خلال الكتابة.\r\n\r\nالعصر العباسي يعتبر من أزهى عصور الأدب العربي. شهدت هذه الفترة نهضة فكرية وأدبية استثنائية، حيث ازدهرت جميع أنواع الأدب من الشعر والنثر والنقد. ظهر شعراء عظماء مثل أبو نواس والمتنبي والمعري، وكتاب متميزون مثل الجاحظ وابن قتيبة. كانت بغداد مركزاً ثقافياً عظيماً يجتذب الشعراء والكتاب والعلماء من كل أنحاء العالم الإسلامي.\r\n\r\nالنثر العربي تطور بشكل كبير عبر العصور. ظهرت أشكال جديدة من النثر مثل المقامات والفنون الأدبية الأخرى. من أشهر كتاب النثر العربي الجاحظ الذي كتب عن الحيوان بطريقة فكاهية وساخرة، وأبو حيان التوحيدي الذي كتب مقالات فلسفية عميقة.\r\n\r\nالرسائل الديوانية احتلت مكاناً مهماً في الأدب العربي. كانت هذه الرسائل بمثابة فن أدبي راقي، وكاتب الرسائل كان يتمتع بمكانة عالية في البلاط السلطاني. يحتوي ديوان الرسائل على أفكار عميقة ولغة جميلة وأسلوب متميز.\r\n\r\nالأدب الأندلسي يمثل حقبة مهمة من تاريخ الأدب العربي. في الأندلس، امتزج الأدب العربي بالتقاليد الإسبانية والأمازيغية، مما أنتج نمطاً أدبياً فريداً. ظهر شعراء أندلسيون عظماء مثل ابن زيدون والمعتمد بن عباد، وكتبوا شعراً رومانسياً عاطفياً.\r\n\r\nالنقد الأدبي ظهر في الثقافة العربية منذ وقت مبكر. نقاد مثل قدامة بن جعفر والآمدي والقاضي الجرجاني وضعوا أسساً للنقد الأدبي العربي. ركزوا على تحليل الأعمال الأدبية وتقييمها بناءً على معايير فنية وجمالية.\r\n\r\nالأدب الحديث والمعاصر شهد تطورات كبيرة. ظهرت أشكال أدبية جديدة مثل الرواية والقصة القصيرة والمسرحية. أدباء مثل نجيب محفوظ وإميل حبيبي وجابر إبراهيم جابر أحدثوا ثورة في الأدب العربي. كما برز شعراء حداثيون مثل نزار قباني وأدونيس الذين جددوا الشعر العربي وأدخلوا أساليب فنية جديدة.", new DateTime(2025, 1, 5, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Arabic+Literature", "الأدب العربي القديم وتطوره عبر العصور" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 4,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "أ.د محمود الفقي", 12, "النظام السياسي الإسلامي في العصور الوسطى كان نموذجاً متقدماً للحكم، تطور من خلال التجربة والاجتهاد. تميز هذا النظام بالعدل والشورى والمساواة أمام القانون، وهي مبادئ استمدت من القرآن الكريم والسنة النبوية.\r\n\r\nالخلافة الإسلامية كانت النظام الأساسي للحكم في الدول الإسلامية. الخليفة كان يعتبر نائب الرسول صلى الله عليه وسلم، ويتحمل مسؤولية حماية الدين وتطبيق الشريعة الإسلامية. لكن السلطة لم تكن مطلقة، فقد كانت مقيدة بالشريعة الإسلامية والالتزام بمشورة العلماء والشعب.\r\n\r\nالشورى أصبحت من أهم مبادئ النظام السياسي الإسلامي. نص القرآن الكريم على أهمية الشورى في قول الله تعالى: وأمرهم شورى بينهم. كانت هناك مجالس للشورى يشارك فيها العلماء والقادة والأشخاص البارزون لإبداء آرائهم في القرارات المهمة.\r\n\r\nالعدل كان من أهم أسس النظام السياسي الإسلامي. نصت الشريعة الإسلامية على المساواة بين جميع الأفراد أمام القانون، بغض النظر عن الثروة أو النسب. حتى الخليفة نفسه لا يمكن أن يكون فوق القانون، وكان يمكن محاكمته إذا انتهك حقوق الشعب.\r\n\r\nالقضاء كان يتمتع باستقلالية نسبية في النظام الإسلامي. القاضي كان يصدر أحكامه بناءً على الشريعة الإسلامية، دون خوف من السلطة الحاكمة. هناك قصص معروفة عن قضاة رفضوا أوامر الخليفة لأنها تخالف الشريعة الإسلامية.\r\n\r\nالشرطة والأمن كانوا تحت إشراف الدولة، مع وجود مسؤول يُعرف بصاحب الشرطة. كانت مهمتهم الحفاظ على الأمن والنظام في المدينة ومعاقبة المجرمين. كانت هناك قوانين صارمة لمعاقبة المسؤولين الذين يساؤون استخدام سلطتهم.\r\n\r\nالنظام الضريبي الإسلامي قام على مبدأ العدالة. الزكاة كانت الضريبة الرئيسية على الثروة، وتُستخدم لمساعدة الفقراء والمحتاجين. كما كانت هناك ضرائب أخرى مثل الجزية على غير المسلمين، لكن الإسلام حرم الضرائب الجائرة.\r\n\r\nالديوان كان الجهاز الإداري الرئيسي للدولة الإسلامية. كان يتولى تنظيم شؤون الدولة من المالية والجيش إلى الحكم. تطور الديوان عبر العصور، واستقبل تأثيرات من النظم الإدارية الساسانية والبيزنطية.\r\n\r\nالجيش كان تحت إشراف الدولة، مع وجود قائد عام يُعرف بأمير الجيش. كانت هناك قوانين عسكرية صارمة تنظم تصرفات الجند وتحافظ على النظام. حقوق الجنود كانت محمية، ويحصلون على رواتب منتظمة وامتيازات معينة.\r\n\r\nالنظام السياسي الإسلامي حافظ على التوازن بين السلطة والحرية. لم يكن الحاكم مستبداً كاملاً، بل كان مقيداً بالقانون والدستور. كما أن الشعب لم يكن بدون صوت، فكان له الحق في الشورى والاعتراض على الأحكام الجائرة.", new DateTime(2025, 1, 6, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Islamic+Politics", "النظام السياسي الإسلامي في العصور الوسطى" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 5,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. علي السيد", 5, "الفتوحات الإسلامية تمثل حقبة مهمة من التاريخ الإنساني، حيث انتشر الإسلام من جزيرة العرب إلى أوروبا وآسيا وأفريقيا في غضون قرن واحد. كانت هذه الفتوحات نتيجة لرغبة المسلمين في نشر الدعوة الإسلامية وتوسيع حدود الدولة الإسلامية.\r\n\r\nفي عهد الخليفة الأول أبي بكر الصديق، بدأت الفتوحات الإسلامية في بلاد الشام والعراق. كانت الجيوش الإسلامية تتمتع بروح عالية وقيادة قوية، مما جعلها قادرة على هزيمة الجيوش البيزنطية والساسانية. فتح المسلمون مدناً مهمة مثل دمشق والقدس والكوفة والبصرة.\r\n\r\nفي عهد عمر بن الخطاب، تسارعت وتيرة الفتوحات بشكل كبير. فتح المسلمون بلاد الشام كاملة، والعراق، وبدأوا في التوسع نحو مصر والشمال الأفريقي. حقق المسلمون انتصارات حاسمة في معركة اليرموك سنة 13 هـ، وهزموا الجيش البيزنطي الكبير.\r\n\r\nفتح مصر كان من أهم الفتوحات الإسلامية. بقيادة عمرو بن العاص، فتح المسلمون مصر وحكموها بعدل. أسس عمرو مدينة الفسطاط التي أصبحت عاصمة مصر الإسلامية. مصر أصبحت مركزاً ثقافياً واقتصادياً مهماً في الدولة الإسلامية.\r\n\r\nالفتوحات أدت إلى انتشار الإسلام على نطاق واسع. معظم سكان بلاد الشام والعراق ومصر اعتنقوا الإسلام بعد الفتح. كان هناك تسامح إسلامي تجاه أهل الذمة الذين بقوا على دينهم، حيث كانوا يدفعون الجزية مقابل الحماية.\r\n\r\nالنظام الإداري الجديد الذي فرضه المسلمون أحدث تغييراً كبيراً في حياة السكان. بدلاً من الاضطهاد البيزنطي والساساني، وجد السكان دولة إسلامية عادلة تطبق الشريعة الإسلامية. انخفضت الضرائب، وتحسنت الخدمات العامة مثل الطرق والقنوات المائية.\r\n\r\nالفتوحات الإسلامية كان لها تأثير كبير على النظام العالمي. تحول التوازن العالمي من الهيمنة البيزنطية والساسانية إلى ظهور قوة إسلامية جديدة. أصبحت الدولة الإسلامية من أقوى الدول في العالم القديم.\r\n\r\nالتبادل الثقافي والحضاري نتج عن الفتوحات الإسلامية. امتزجت الثقافة الإسلامية بالثقافات الحالية المحلية، مما أنتج حضارة إسلامية غنية ومتنوعة. استقبل المسلمون المعارف الإغريقية والفارسية والهندية، وساهموا في الحفاظ عليها وتطويرها.\r\n\r\nالمعاملة الإنسانية للسكان المفتوحة كانت من مميزات الفتوحات الإسلامية. وضع الخليفة عمر بن الخطاب شروطاً على القيادات العسكرية بعدم ظلم السكان واحترام معتقداتهم. كان هناك احترام لحقوق السكان المحليين وممتلكاتهم.\r\n\r\nأدى التوسع الإسلامي إلى زيادة النشاط الاقتصادي والتجاري. الطرق التجارية بين الشرق والغرب أصبحت آمنة تحت الحكم الإسلامي. مدن جديدة أُسست لتصبح مراكز تجارية وسياسية، مما عزز الازدهار الاقتصادي.", new DateTime(2025, 1, 7, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Islamic+Conquests", "الفتوحات الإسلامية وتأثيرها على العالم" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 6,
                columns: new[] { "AuthorName", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. نورا الشاعرة", "الشعر العربي يعتبر من أسمى أشكال التعبير الأدبي والفني. على مدى آلاف السنين، استخدم الشعراء العرب الشعر للتعبير عن مشاعرهم وأفكارهم وقيمهم. لكل عصر من العصور شعراؤه المميزون الذين تركوا لنا روائع شعرية خالدة.\r\n\r\nالشعر الجاهلي كان يعبر عن حياة الجاهليين قبل الإسلام. كانوا يكتبون عن الحب والحرب والفخر والهجاء والرثاء. شعراء مثل امرؤ القيس كتب شعراً رومانسياً جميلاً عن الحب، بينما عنترة كتب عن الفرسالة والشجاعة.\r\n\r\nأغراض الشعر العربي متعددة ومتنوعة. الغزل كان من أهم الأغراض الشعرية، حيث عبّر الشعراء عن مشاعرهم تجاه محبوباتهم. كانوا يوصفون جمال المرأة ويشكون من معاناة الحب والفراق. الشعر الغزلي تطور عبر العصور، من الغزل البدوي الخشن إلى الغزل الحضري الرقيق.\r\n\r\nالفخر والمدح كان أغراضاً شعرية مهمة. كان الشعراء يفخرون بقبائلهم وآبائهم وأنفسهم، ويمدحون الملوك والأمراء الذين يعطونهم الجوائز والهدايا. كانت هذه الأغراض وسيلة لكسب العيش والحصول على الحماية.\r\n\r\nالهجاء كان فناً شعرياً مهماً في التراث العربي. كان الشعراء يهاجمون أعدائهم وخصومهم بألفاظ قاسية وصور ساخرة. كان الهجاء سلاحاً فعالاً يستخدمه الشعراء لتشويه سمعة الخصم والانتقام منه.\r\n\r\nالرثاء كان تعبيراً عن الحزن والأسف على فقدان الأحبة. كتب الشعراء أشعاراً جميلة في رثاء الملوك والشهداء والأقارب. كانوا يصفون محاسن الميت وينوحون على فقدانهم.\r\n\r\nالوصف كان فناً شعرياً راقياً، حيث يصف الشاعر الطبيعة والحيوانات والمدن بطريقة حسية وجميلة. كانوا يصفون الصحراء والخيل والنسور والطير بتفاصيل دقيقة وصور رائعة.\r\n\r\nالشعر الديني ظهر بعد الإسلام، حيث استخدم الشعراء الشعر للدفاع عن الدين الإسلامي والتبشير به. حسان بن ثابت كان شاعر الرسول صلى الله عليه وسلم، وكتب شعراً في الدفاع عن الإسلام ضد هجمات المشركين.\r\n\r\nالشعر الاجتماعي عالج قضايا مجتمعية مهمة مثل الظلم والفقر والاستبداد. شعراء حديثون مثل أحمد شوقي وحافظ إبراهيم استخدموا الشعر للتحدث عن قضايا الأمة والمجتمع.\r\n\r\nالشعر الحر والحديث جدد الشعر العربي بتكسير القيود التقليدية. شعراء مثل نزار قباني وأدونيس كتبوا شعراً حراً لا يلتزم بالقافية والوزن التقليديين. أضافوا بعداً نفسياً وفلسفياً عميقاً للشعر العربي.", new DateTime(2025, 1, 8, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Arabic+Poetry", "الشعر العربي وأغراضه المختلفة" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 7,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. خالد النبوي", 5, "الخلافة العباسية تمثل قمة ازدهار الحضارة الإسلامية في الوسط الإسلامي. استمرت هذه الخلافة من سنة 132 هـ إلى سنة 656 هـ، وكانت فترة ذهبية للعلوم والفنون والآداب والفلسفة.\r\n\r\nقام الخليفة أبو جعفر المنصور بتأسيس عاصمة جديدة للدولة بغداد سنة 145 هـ. كانت بغداد مدينة حديثة ومنظمة، تجمع بين الفن والعمارة الإسلامية. أصبحت بغداد مركزاً ثقافياً وعلمياً عظيماً يجذب العلماء والفلاسفة من كل أنحاء العالم الإسلامي.\r\n\r\nالحياة العلمية في الخلافة العباسية كانت ازدهاراً حقيقياً. أسس الخليفة المأمون بيت الحكمة في بغداد، وهو مركز للترجمة والدراسة. كانوا يترجمون الكتب اليونانية والفارسية والهندية إلى العربية، مما حافظ على المعارف القديمة وطورها.\r\n\r\nالرياضيات كانت من أهم العلوم التي ازدهرت في العصر العباسي. عالم الرياضيات الخوارزمي وضع أسس الجبر والخوارزميات. ظهر علماء عظماء مثل الكندي والفارابي والبيروني الذين ساهموا بشكل كبير في تطور الرياضيات والعلوم الأخرى.\r\n\r\nالطب والعلوم الطبيعية شهدت تطوراً كبيراً. أسس العباسيون أول مستشفيات إسلامية منظمة. طبيب مثل الرازي وابن سينا قدموا مساهمات عظيمة في الطب والصيدلة. كانت هناك كتب طبية مهمة تُرجمت من اليونانية وتطورت بناءً على التجارب الإسلامية الجديدة.\r\n\r\nالفلسفة الإسلامية تطورت بشكل كبير في هذا العصر. فلاسفة مثل الكندي والفارابي وابن سينا حاولوا التوفيق بين الفلسفة اليونانية والعقيدة الإسلامية. كانوا يناقشون قضايا متعلقة بوجود الله والعقل والمعرفة والكون.\r\n\r\nالأدب العربي ازدهر بشكل استثنائي في العصر العباسي. ظهر شعراء عظماء مثل أبي نواس والبحتري والمتنبي. كانوا يكتبون شعراً راقياً عن مواضيع مختلفة من الحب والفخر والسياسة. كما نمت فنون أدبية جديدة مثل المقامات والفنون النثرية الأخرى.\r\n\r\nالفنون الإسلامية والعمارة وصلت إلى ذروة جمالها. بني العباسيون مساجد وقصور وحصون جميلة. الزخرفة الهندسية والخطط اتبعت مبادئ فنية عالية. كانت العمارة العباسية تجمع بين التأثيرات الفارسية والبيزنطية والعربية.\r\n\r\nالاقتصاد العباسي كان قوياً ومزدهراً. طرق التجارة الرئيسية بين الشرق والغرب كانت تحت السيطرة العباسية. المدن التجارية مثل بغداد والبصرة ودمشق كانت مراكز اقتصادية حية. كان هناك تبادل تجاري مكثف مع الصين والهند وأوروبا.\r\n\r\nالحياة الاجتماعية في العصر العباسي كانت معقدة ومتنوعة. كانت هناك طبقات اجتماعية مختلفة من الخلفاء والوزراء والعلماء إلى الحرفيين والعمال. كانت هناك نساء عالمات وأديبات مثل سراقة وغيرهن تركن بصماتهن على الحضارة العباسية.", new DateTime(2025, 1, 9, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Abbasid+Caliphate", "الخلافة العباسية وازدهار الحضارة الإسلامية" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 8,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "أ.د ليلى الحكيم", 12, "النظم السياسية الحديثة تطورت عبر قرون من الصراعات والتجارب والأفكار الفلسفية. الديمقراطية أصبحت النموذج المفضل للعديد من الدول في العالم. لكن هناك نقاشات دائمة حول أفضل نظام سياسي وكيفية تطبيقه بفعالية.\r\n\r\nالديمقراطية بمعناها الأساسي هي حكم الشعب للشعب. الفكرة الأساسية هي أن السلطة تنبع من الشعب، وأن المواطنين لهم الحق في المشاركة في صنع القرارات التي تؤثر على حياتهم. كانت الديمقراطية اليونانية القديمة أول نموذج لهذا النوع من الحكم.\r\n\r\nالديمقراطية البرلمانية نظام سياسي يقسم السلطة بين البرلمان والحكومة والملك. البرلمان يمثل الشعب ويسن القوانين، والحكومة تنفذ هذه القوانين، والملك يكون رأس الدولة. هذا النظام موجود في دول مثل بريطانيا وكندا واستراليا.\r\n\r\nالديمقراطية الرئاسية نظام آخر حيث الرئيس هو رأس الدولة ورئيس الحكومة في نفس الوقت. السلطة التشريعية والتنفيذية تكون منفصلة. هذا النظام موجود في دول مثل الولايات المتحدة والبرازيل والمكسيك.\r\n\r\nالديمقراطية المباشرة تسمح للمواطنين بالتصويت مباشرة على القضايا المهمة. في الديمقراطيات الحديثة، تُستخدم استفتاءات واستطلاعات الرأي لأخذ رأي الشعب في قضايا معينة. سويسرا تمارس نوعاً من الديمقراطية المباشرة حيث المواطنون يصوتون على القوانين والقرارات المهمة.\r\n\r\nالدستور يعتبر الأساس القانوني لأي نظام سياسي حديث. يحدد الدستور الحقوق والواجبات للمواطنين والحكومة. يضمن الحقوق الأساسية مثل حرية التعبير والدين والتجمع. الفصل بين السلطات من المبادئ الأساسية في الدساتير الحديثة.\r\n\r\nحقوق الإنسان أصبحت مبدأً أساسياً في النظم السياسية الحديثة. الإعلان العالمي لحقوق الإنسان يضمن الكرامة والمساواة والحرية لكل فرد. يجب على الحكومات احترام هذه الحقوق وحمايتها.\r\n\r\nالمؤسسات الديمقراطية مثل الانتخابات والأحزاب السياسية والإعلام الحر هي ضروية لأي ديمقراطية ناجحة. الانتخابات الحرة والنزيهة هي الطريقة التي يختار بها الشعب ممثليهم. الأحزاب السياسية توفر منصات مختلفة للأفكار والسياسات.\r\n\r\nالفساد والمحسوبية يعتبران تهديداً كبيراً للأنظمة الديمقراطية. يجب أن تكون هناك آليات قوية لمكافحة الفساد والشفافية في الحكومة. المساءلة والمراقبة ضرورية للحفاظ على سلامة النظام السياسي.\r\n\r\nالعدالة الاجتماعية مبدأ مهم في الديمقراطيات الحديثة. يجب أن توفر الحكومات فرصاً متساوية للتعليم والعمل والرعاية الصحية. محاربة الفقر والبطالة ضرورية لمجتمع ديمقراطي صحي.", new DateTime(2025, 1, 10, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Democracy", "النظم السياسية الحديثة والديمقراطية" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 9,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. عمر الفنان", 13, "المقامات تعتبر فناً أدبياً عربياً فريداً لا نظير له في الآداب الأخرى. هذا الفن تطور في العصور الإسلامية المختلفة، وأصبح من أهم أشكال الأدب النثري العربي. المقامة عبارة عن نصوص أدبية قصيرة، مكتوبة بأسلوب أدبي راقي تجمع بين السجع والسرد والشعر.\r\n\r\nمؤسس فن المقامات يعتبر بديع الزمان الهمذاني الذي ألف أول مجموعة من المقامات في القرن الرابع الهجري. كتب نحو خمسين مقامة تتحدث عن مغامرات شخصيات مختلفة. نموذج الراوي والبطل ظهر بوضوح في مقاماته، حيث يروي الراوي قصة البطل الذي يسمى أبو الفتح الإسكندري.\r\n\r\nالحريري جاء بعد الهمذاني وطور فن المقامات إلى آفاق جديدة. كتب الحريري نحو خمسين مقامة أيضاً، لكن بأسلوب مختلف أكثر دقة وفلسفة. مقامات الحريري تحتوي على أفكار أخلاقية وفلسفية عميقة، وتعالج قضايا اجتماعية مهمة.\r\n\r\nالمقامة تتكون من عدة عناصر أساسية. هناك البطل الذي يقوم بدور الشخصية الرئيسية والراوي الذي يحكي القصة. القصة عادة ما تدور حول مغامرة طريفة أو موقف فكاهي. اللغة تكون مزيجاً من الفصيحة والسجع والأسلوب الأدبي الرفيع.\r\n\r\nالأسلوب الأدبي في المقامات يتميز بالزخرفة اللغوية والسجع المتقن. الكاتب يحاول أن يثير إعجاب القارئ بجمال اللغة والتعبير. الجمل تكون قصيرة وموزونة، والألفاظ تكون مختارة بعناية. هناك استخدام كثيف للتشبيهات والاستعارات.\r\n\r\nالهدف الفكاهي والترفيهي يشكل جزءاً كبيراً من المقامات. كثيراً ما يجد القارئ نفسه يضحك من الحالات الطريفة والموضوعات الهزلية. البطل غالباً ما يكون شخصية ماكرة تحاول الحصول على ما تريد بطرق ذكية أحياناً وماكرة أحياناً أخرى.\r\n\r\nالمقامات تعالج قضايا اجتماعية واقتصادية مهمة. تصف حياة الطبقات المختلفة في المجتمع، من الأغنياء والعلماء إلى الفقراء والمشردين. تنتقد الجهل والظلم والفساد بطريقة ساخرة وفكاهية.\r\n\r\nالتطور التاريخي للمقامات شهد تطورات مهمة. مع مرور الوقت، ظهرت مقامات جديدة لكتاب مختلفين، كل واحد أضاف لمسته الخاصة على الفن. ظهرت مقامات في الشام والعراق ومصر والأندلس، لكل منطقة خصائصها الثقافية.\r\n\r\nالتأثير الأدبي للمقامات امتد عبر القرون. تأثرت الأشكال الأدبية الأخرى بفن المقامات، مثل الرواية والقصة القصيرة. المقامات أثرت على تطور الأدب العربي الحديث، وساهمت في تشكيل ذوق أدبي راقي.\r\n\r\nفي العصر الحديث، حاول بعض الكتاب إحياء فن المقامات. كتاب مثل ناجي الحاج وغيره كتبوا مقامات حديثة تجمع بين التقليد الأدبي القديم والأساليب الحديثة. لكن المقامات الكلاسيكية تبقى الأساس والمرجع الأساسي.", new DateTime(2025, 1, 10, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Arabic+Maqamat", "المقامات والسرد في الأدب العربي" });

            migrationBuilder.UpdateData(
                table: "Articles",
                keyColumn: "Id",
                keyValue: 10,
                columns: new[] { "AuthorName", "CategoryId", "Content", "CreatedAt", "FeaturedImageUrl", "Title" },
                values: new object[] { "د. منى الحكيم", 12, "الحرية والعدالة تعتبران من أهم القيم الإنسانية، وقد أعطى الإسلام هذين المفهومين أهمية قصوى. الفكر السياسي الإسلامي تطور على مبادئ الحرية والعدالة، والتي أُشير إليها في القرآن الكريم والسنة النبوية.\r\n\r\nالحرية في الإسلام لا تعني الحرية المطلقة بدون حدود، بل هي حرية في إطار الشريعة الإسلامية. الفرد له الحق في أن يختار دينه وآراءه ومهنته، طالما لا يضر الآخرين ويلتزم بقيم المجتمع. القرآن الكريم يؤكد على حرية الاختيار في قول الله تعالى: لا إكراه في الدين.\r\n\r\nالعدالة في الإسلام تعني المساواة وإعطاء كل ذي حق حقه. الشريعة الإسلامية تضمن العدالة في جميع جوانب الحياة من القضاء إلى المعاملات التجارية. القاضي الإسلامي يجب أن يكون عادلاً ومحايداً، ولا يمكن أن يحابي غنياً لغناه أو فقيراً لفقره.\r\n\r\nحقوق الإنسان في الإسلام محمية بشكل قوي. حرمة الدم والمال والعرض محمية بالشريعة الإسلامية. لا يمكن أن يُقتل الإنسان بدون حق، ولا يمكن أن تُؤخذ أمواله بدون وجه حق. كما يُحمى من الظلم والاستبداد.\r\n\r\nالحقوق المدنية والسياسية كفلها الإسلام لجميع المواطنين. الحق في التعليم والعمل والتملك محمي. كما أن الفرد له الحق في المشاركة في شؤون الدولة من خلال الشورى والانتخابات.\r\n\r\nحقوق المرأة في الإسلام لا تختلف عن حقوق الرجل في الأساسيات. المرأة لها الحق في التعليم والعمل والملكية والطلاق. الإسلام حرم الظلم والتمييز ضد النساء، وأعطاهن مكانة عالية في المجتمع.\r\n\r\nحقوق العمال والموظفين محمية بالشريعة الإسلامية. لهم الحق في أجر عادل وظروف عمل آمنة. الإسلام حرّم استغلال العمال والعبيد، وأمر بمعاملتهم بعدل وإحسان.\r\n\r\nحرية الرأي والتعبير مضمونة في الإسلام، لكن ضمن حدود لا تتعارض مع الشريعة الإسلامية. الفرد له الحق في أن يبدي رأيه في قضايا الدولة، والخليفة يجب أن يستمع إلى آراء رعاياه. النقد البناء مسموح به، وحتى الاختلاف في الرأي مقبول إذا كان بحسن نية.\r\n\r\nالعقوبات في الشريعة الإسلامية عادلة ومتناسبة مع الجرم. لا تُطبق العقوبة على المخطئ الذي تاب وعاد عن معصيته. كما أن الشريعة تضمن حقوق المتهم، فله الحق في الدفاع عن نفسه والمحاكمة العادلة.\r\n\r\nالتطبيق الحديث لمبادئ الحرية والعدالة الإسلامية يتطلب فهماً عميقاً للقيم الإسلامية وتطبيقها بطريقة تتوافق مع الواقع المعاصر. يجب الموازنة بين الحفاظ على القيم الإسلامية والاستجابة لمتطلبات العصر الحديث.", new DateTime(2025, 1, 11, 0, 0, 0, 0, DateTimeKind.Utc), "https://via.placeholder.com/400x300?text=Islamic+Justice", "الحرية والعدالة في الفكر السياسي الإسلامي" });
        }
    }
}
